var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}

var formationId = data.id ? esc(String(data.id)) : null;
var membreId = data.membreId ? esc(String(data.membreId)) : null;

if (!formationId) throw new Error('Missing formation id');
if (!membreId) throw new Error('Missing membreId');

var id = require('crypto').randomUUID();

// Requête en 2 étapes: vérifier places dispo puis insérer
// On utilise un CTE pour vérifier atomiquement
var query = "WITH check_places AS (" +
  "SELECT f.id, f.max_participants, " +
  "(SELECT COUNT(*) FROM rh_inscriptions_formations WHERE formation_id = f.id) as nb_inscrits " +
  "FROM rh_formations f WHERE f.id = '" + formationId + "' AND f.tenant_id = '" + esc(tenantId) + "'" +
  "), " +
  "check_doublon AS (" +
  "SELECT id FROM rh_inscriptions_formations WHERE formation_id = '" + formationId + "' AND member_id = '" + membreId + "'" +
  ") " +
  "INSERT INTO rh_inscriptions_formations (id, tenant_id, formation_id, member_id, date_inscription) " +
  "SELECT '" + esc(id) + "', '" + esc(tenantId) + "', '" + formationId + "', '" + membreId + "', NOW() " +
  "FROM check_places " +
  "WHERE check_places.nb_inscrits < check_places.max_participants " +
  "AND NOT EXISTS (SELECT 1 FROM check_doublon) " +
  "RETURNING *, " +
  "(SELECT CASE WHEN EXISTS (SELECT 1 FROM check_doublon) THEN 'doublon' " +
  "WHEN (SELECT nb_inscrits FROM check_places) >= (SELECT max_participants FROM check_places) THEN 'complet' " +
  "ELSE 'ok' END) as check_result;";

return [{json: {query: query}}];

var row = $input.first().json;
if (!row || !row.id) {
  // Pas d'insertion = soit doublon soit formation complète
  return [{json: {success: false, error: "Inscription impossible : formation complète ou membre déjà inscrit"}}];
}
return [{json: {success: true, data: {
  id: row.id,
  tenantId: row.tenant_id,
  formationId: row.formation_id,
  memberId: row.member_id,
  dateInscription: row.date_inscription,
  statut: row.statut || 'inscrit'
}}}];
